sequence.script:
// -------------------------------
// Read quoteId from context
// -------------------------------
var quoteId = mc.getProperty("quoteId");

// -------------------------------
// Format current date
// -------------------------------
function formatDate(dateObj) {
    return dateObj.toLocaleString("en-US", {
        month: "long",
        day: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true
    });
}

var nowFormatted = formatDate(new Date());

// -------------------------------
// Subject
// -------------------------------
var subject = "Quote Discarded: " + quoteId;
mc.setProperty("mail.smtp.subject", subject);
mc.setProperty("Email_Subject", subject);

// -------------------------------
// HTML Body
// -------------------------------
var emailBody =
'<!doctype html>' +
'<html lang="en">' +
'<head>' +
'  <meta charset="utf-8">' +
'  <meta name="viewport" content="width=device-width, initial-scale=1.0" />' +
'  <style>' +
'    body { margin:0; padding:0; font-family:Arial, Helvetica, sans-serif; background:#f4f6f8; color:#333; }' +
'    .container { max-width:700px; margin:20px auto; background:#fff; border-radius:6px; box-shadow:0 2px 6px rgba(0,0,0,0.15); }' +
'    .header { background:#6c757d; padding:24px; text-align:center; color:#fff; font-size:26px; font-weight:bold; }' +
'    .body { padding:30px; font-size:15px; line-height:1.6; }' +
'    .footer { padding:20px; text-align:center; font-size:12px; color:#9aa7bf; }' +
'  </style>' +
'</head>' +
'<body>' +
'  <div class="container">' +
'    <div class="header">Quote Discarded</div>' +
'    <div class="body">' +
'      <p>' + nowFormatted + '</p>' +
'      <p>Dear User,</p>' +
'      <p>We would like to inform you that your insurance quote <strong>' + quoteId + '</strong> has been <strong>discarded</strong> by <strong>Exasure IIC</strong>.</p>' +
'      <p>This action was taken as the quote was either expired, withdrawn, or did not meet the required criteria.</p>' +
'      <div style="margin:25px 0; text-align:center;">' +
'        <a href="http://localhost:5173/home" style="background:#6c757d; color:#ffffff; padding:12px 22px; text-decoration:none; font-size:15px; font-weight:bold; border-radius:6px;">Get a New Quote</a>' +
'      </div>' +
'      <p>Thank you for considering <strong>Exasure IIC</strong>.</p>' +
'      <p>Sincerely,<br><strong>Exasure IIC</strong><br>Policy & Customer Support</p>' +
'    </div>' +
'    <div class="footer">' +
'      Exasure IIC | http://localhost:5173/home<br>' +
'      This is an automated message. Please do not reply.' +
'    </div>' +
'  </div>' +
'</body>' +
'</html>';

mc.setProperty("Email_Body", emailBody);
